import{c as n,Q as t,j as s,m as i}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"解释器系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../interpreterLearning/00-写作计划.md","filePath":"../interpreterLearning/00-写作计划.md","lastUpdated":1778496697000}'),l={name:"../interpreterLearning/00-写作计划.md"};function e(o,a,r,p,h,c){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="解释器系列写作计划" tabindex="-1">解释器系列写作计划 <a class="header-anchor" href="#解释器系列写作计划" aria-label="Permalink to &quot;解释器系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第五类「推荐组合」特别推荐项,⭐⭐⭐⭐。 写一门解释器是「最反直觉但回报极高」的训练——动一次手,JS / Dart / Python / Rust 里所有看起来&quot;语言自带&quot;的东西(作用域 / 闭包 / GC / 异常 / 模块)就突然全部塌缩成&quot;你昨天刚写过的几十行代码&quot;。 <strong>看完这层,你读 V8 / CPython / JVM 源码会快一个量级</strong>,写 DSL / 模板引擎 / 配置语言 / 规则引擎时会长出「解析器的本能」,而不是再用一堆 if/else 和正则硬拼。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,<strong>贯穿动手实现一门小语言 Mochi</strong>——从源码字符流一路推到字节码 VM 跑起来,再补 GC 和 JIT 的心智:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智与基础(解释器 vs 编译器 vs JIT / 一段代码怎么跑起来)</span></span>
<span class="line"><span>   → 前端(词法 / 语法 / 递归下降 / Pratt parser)</span></span>
<span class="line"><span>   → 树遍历解释器(AST / 求值 / 作用域 / 闭包)</span></span>
<span class="line"><span>   → 进阶语义(类 / 模块 / 类型系统 / 元编程)</span></span>
<span class="line"><span>   → 字节码虚拟机(为什么要 VM / 栈式 vs 寄存器式 / 编译器)</span></span>
<span class="line"><span>   → 运行时与未来(GC / JIT / 真实语言剖析)</span></span></code></pre></div><p><strong>这个系列不是《Crafting Interpreters》翻译</strong>——那本书结构是教学,先把整本 Lox 一次性走完;<strong>本系列偏&quot;工程师视角&quot;</strong>:每篇都对应一个&quot;语言里你天天用却没拆过的特性&quot;,讲清楚它怎么实现、工业级是怎么做、有哪些优化方向。</p><p>不深入到编译原理证明、不啃龙书,<strong>而是讲清楚&quot;应用工程师能动手做、需要懂的语言实现图景&quot;</strong>——读完应该:</p><ol><li>手上有一门能跑的小语言 Mochi,从树遍历版本一直到字节码 VM 版本</li><li>看 CPython / V8 / Lua 源码大致能对上号</li><li>下次写配置 / DSL / 规则引擎,<strong>第一反应是&quot;先定义文法&quot;,不是写正则</strong></li></ol><p>参考蓝本:Bob Nystrom《Crafting Interpreters》、Thorsten Ball《Writing An Interpreter in Go》/《Writing A Compiler in Go》、Andrew Appel《Modern Compiler Implementation》。</p><hr><h2 id="小语言-mochi" tabindex="-1">小语言:Mochi <a class="header-anchor" href="#小语言-mochi" aria-label="Permalink to &quot;小语言:Mochi&quot;">​</a></h2><blockquote><p>mochi(麻糬)——软、糯、Q弹、能塞进各种馅料。</p><p>Mochi 是本系列贯穿始终的玩具语言,目标定位:</p><ul><li>动态类型,语法风味介于 Python 和 JS 之间</li><li>一等公民函数 + 闭包 + 类 + 模块</li><li>树遍历版本(01-19)→ 字节码 VM 版本(20-25)→ 加 GC(26-27)</li><li>宿主语言:TypeScript 为主(读者基数广),关键算法附 Rust 版本(贴近工业级)</li></ul></blockquote><p>每一篇的代码都在前一篇的 Mochi 仓库上叠加,<strong>不是孤立的玩具</strong>——25 篇之后,Mochi 应该能跑一段含闭包、类、模块、try/catch 的脚本,并在字节码 VM 上比树遍历快 5-10 倍。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-04" tabindex="-1">第一层:心智与基础(01-04) <a class="header-anchor" href="#第一层-心智与基础-01-04" aria-label="Permalink to &quot;第一层:心智与基础(01-04)&quot;">​</a></h3><ul><li>[x] 01 解释器总览(为什么写解释器是元能力 / 解释器 vs 编译器 vs JIT 三种姿态)</li><li>[x] 02 一段代码怎么跑起来(源码 → token → AST → 求值 / 字节码 → 执行的全景图)</li><li>[x] 03 介绍 Mochi(语法风味 / 类型选择 / 路线图 / 我们最后要长成什么样)</li><li>[x] 04 项目骨架与 REPL(测试驱动 / 错误位置追踪 / 一开始就把基建搭对)</li></ul><h3 id="第二层-前端-词法与语法-05-09" tabindex="-1">第二层:前端 - 词法与语法(05-09) <a class="header-anchor" href="#第二层-前端-词法与语法-05-09" aria-label="Permalink to &quot;第二层:前端 - 词法与语法(05-09)&quot;">​</a></h3><ul><li>[x] 05 词法分析(token 设计 / 手写状态机 / 注释 / 字符串转义 / 错误恢复)</li><li>[x] 06 lexer generator vs 手写(为什么 V8 / CPython / rustc 全是手写)</li><li>[x] 07 文法基础(BNF / EBNF / LL vs LR / 二义性与运算符优先级)</li><li>[x] 08 递归下降解析器(自顶向下 / 同步点 / panic mode 错误恢复)</li><li>[x] 09 Pratt parser(前缀 / 中缀 / 后缀的统一处理 / 表达式优先级再也不写不爽)</li></ul><h3 id="第三层-树遍历解释器-10-15" tabindex="-1">第三层:树遍历解释器(10-15) <a class="header-anchor" href="#第三层-树遍历解释器-10-15" aria-label="Permalink to &quot;第三层:树遍历解释器(10-15)&quot;">​</a></h3><ul><li>[x] 10 AST 设计(节点类型 / Visitor 模式 / 代数数据类型 / 为什么不要 OOP 重载)</li><li>[x] 11 表达式求值(字面量 / 运算 / 短路 / 真值语义 / 隐式转换的坑)</li><li>[x] 12 变量与作用域(环境链 / 词法 vs 动态作用域 / 变量解析 pass 与 hoisting)</li><li>[x] 13 控制流(if / while / for / break / continue / 异常的非局部跳转)</li><li>[x] 14 函数与闭包(一等公民 / 参数传递 / 捕获语义 / 为什么 JS 的 var 设计错了)</li><li>[x] 15 运行时错误与 REPL(栈追踪 / source map / 交互式开发的快感)</li></ul><h3 id="第四层-进阶语义-16-19" tabindex="-1">第四层:进阶语义(16-19) <a class="header-anchor" href="#第四层-进阶语义-16-19" aria-label="Permalink to &quot;第四层:进阶语义(16-19)&quot;">​</a></h3><ul><li>[x] 16 类与继承(对象怎么&quot;长&quot;出来 / 方法分派 / 单继承 vs 原型 / super 的实现)</li><li>[x] 17 模块系统(命名空间 / import 语义 / 循环依赖 / CommonJS 与 ESM 之争)</li><li>[x] 18 类型系统初步(动态 / 静态 / 渐进式 / Hindley-Milner 推导直觉)</li><li>[x] 19 元编程入门(eval / 反射 / quote-unquote / Lisp 宏 vs Rust 宏 vs JS Proxy)</li></ul><h3 id="第五层-字节码虚拟机-20-25" tabindex="-1">第五层:字节码虚拟机(20-25) <a class="header-anchor" href="#第五层-字节码虚拟机-20-25" aria-label="Permalink to &quot;第五层:字节码虚拟机(20-25)&quot;">​</a></h3><ul><li>[x] 20 为什么要 VM(树遍历的瓶颈 / 编译到字节码的收益 / 我们要重写 Mochi 后端)</li><li>[x] 21 字节码设计(指令集 / 操作数编码 / 常量池 / 反汇编工具先写好)</li><li>[x] 22 栈式 VM(调度循环 / 计算模型 / 指令分发的几种实现 / computed goto)</li><li>[x] 23 寄存器式 VM(Lua / Dalvik 的选择 / 指令更少但编译器更复杂)</li><li>[x] 24 编译器:AST 到字节码(单遍编译 / 局部变量编号 / 跳转回填)</li><li>[x] 25 函数调用与闭包(call frame / 返回地址 / upvalue 与逃逸捕获)</li></ul><h3 id="第六层-运行时与未来-26-30" tabindex="-1">第六层:运行时与未来(26-30) <a class="header-anchor" href="#第六层-运行时与未来-26-30" aria-label="Permalink to &quot;第六层:运行时与未来(26-30)&quot;">​</a></h3><ul><li>[x] 26 GC 基础(引用计数 vs 追踪 / mark-sweep / 三色标记 / Mochi 上手写一个)</li><li>[x] 27 GC 进阶(分代 / 增量 / 并发 / 写屏障 / 为什么 V8 和 JVM 都走这条路)</li><li>[x] 28 JIT 心智(模板 JIT / 方法 JIT / Tracing JIT / V8 Ignition+TurboFan 怎么协作)</li><li>[x] 29 真实语言剖析(CPython 字节码 / V8 / Lua / JVM 的核心数据结构对照表)</li><li>[x] 30 从 Mochi 到生产语言(WASM 后端 / 增量编译 / LSP / 你的下一步路线图)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>树 / 栈 / 哈希表</td><td>algorithmLearning/06-11 ✅</td><td>不重复,直接当工具用</td></tr><tr><td>ELF / 加载 / 链接</td><td>osLearning/03 ✅</td><td>不重复,本系列是它&quot;上面一层&quot;:程序怎么运行</td></tr><tr><td>进程 / 线程 / 协程</td><td>osLearning/11-17 ✅</td><td>不重复,GC 篇会引用,但不重讲调度</td></tr><tr><td>Rust / Go / TS 语言层使用</td><td>rustLearning / goLearning / 等 ✅</td><td>不重复,本系列拆&quot;语言怎么实现&quot;,不是&quot;语言怎么用&quot;</td></tr><tr><td>类型系统(Rust 所有权)</td><td>rustLearning ✅</td><td>不重复,只在 18 篇做语言实现视角的对照</td></tr><tr><td>网络 / Web 协议</td><td>networkLearning / webLearning ✅</td><td>无交集</td></tr><tr><td>安全(沙箱逃逸)</td><td>securityLearning ✅</td><td>不重复,Mochi 不展开沙箱攻防</td></tr><tr><td>LLM / Agent</td><td>aiLearning / claudeLearning ✅</td><td>无交集</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇按&quot;它是什么 → 最简实现 → 工业级是怎么做的 → 优化方向&quot;四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 它是什么 / 为什么需要它</span></span>
<span class="line"><span>   - 一句话定义</span></span>
<span class="line"><span>   - 没它的世界长什么样(去掉这个特性,Mochi 哪里就不能写了)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Mochi 里的最简实现</span></span>
<span class="line"><span>   - 30-80 行 TypeScript,跑得通就行</span></span>
<span class="line"><span>   - 重点在结构,不在边界 case</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工业级是怎么做的</span></span>
<span class="line"><span>   - V8 / CPython / Lua / JVM 选 1-2 个,对比关键差异</span></span>
<span class="line"><span>   - 真实数据结构 / 真实优化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 优化方向与下一步</span></span>
<span class="line"><span>   - 这一篇留了哪些坑</span></span>
<span class="line"><span>   - 后面哪一篇会回来填(或者本系列不填,作为留白)</span></span></code></pre></div><p>不堆完整源码——<strong>关键算法只贴 30-80 行 TS,工业级实现只给指针</strong>(类名 / 文件路径 / commit hash),让读者「看一眼知道这一层在干嘛」就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智:看完知道&quot;语言运行时不是魔法,是几千行代码&quot;</span></span>
<span class="line"><span>05-09  前端:**手痒值最高的一层**,写完能解析任意小语言</span></span>
<span class="line"><span>10-15  树遍历:**Mochi 第一次跑起来**,REPL 能 print Hello World 那一刻最爽</span></span>
<span class="line"><span>16-19  语义:看完知道&quot;OOP / 模块 / 类型 在实现层根本没你想的复杂&quot;</span></span>
<span class="line"><span>20-25  字节码:**Mochi 性能爆炸的一层**,实测比树遍历版本快 5-10 倍</span></span>
<span class="line"><span>26-30  运行时:**最值钱的一层**,读 V8 / CPython 源码从此不慌</span></span></code></pre></div><p><strong>硬指标</strong>:看完 25 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 JS 的 <code>let</code> 比 <code>var</code> 安全,在解释器实现层差在哪一步&quot;</li><li>&quot;为什么 CPython 慢,但加 JIT(PyPy / 3.13 的 specializing interpreter)能快好几倍&quot;</li><li>&quot;为什么 Lua 用寄存器式 VM,V8 用栈式,各自的取舍是什么&quot;</li><li>&quot;为什么 Go 不用引用计数,Swift 不用追踪 GC&quot;</li></ul><p>讲清楚其中一题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「先讲编译原理证明 / 龙书第三章」——本系列是工程师视角,不证明文法等价性</li><li>「先讲个语言史 / 个人情怀」——直接进重点,Lisp 是 1958 年发明的,读者来这里不是为了知道这个</li><li>罗列所有 token / 所有 AST 节点——只贴关键 5-10 种,剩下读者自己长出来</li><li>「这是面试常考」——读者来这里是为了真的会写解释器,不是背名词</li><li>抄《Crafting Interpreters》逐章翻译——那本书在那儿,这里补它没讲透的&quot;为什么&quot;</li><li>不画图就讲 AST / 闭包捕获 / GC 三色标记——这些东西<strong>不画图永远讲不清楚</strong></li><li>Mochi 半路换语言风格——一旦定下来,30 篇都是同一门 Mochi,不要写到 20 篇又改语法</li></ol><hr><h2 id="代码语言" tabindex="-1">代码语言 <a class="header-anchor" href="#代码语言" aria-label="Permalink to &quot;代码语言&quot;">​</a></h2><p>宿主语言统一用 <strong>TypeScript</strong>,关键算法附 <strong>Rust</strong> 版本:</p><ul><li>TS 读起来像 Java / JS / C# 的平均,业内接受度最高,跟 webLearning / backendLearning 的代码风格一致</li><li>Rust 贴近工业级解释器(rustc / Deno / 部分 V8 子模块)的工程现实,适合在 GC / VM 篇章引用</li><li>Mochi 源码本身是另一门语言,在文章里以代码块出现,<strong>不需要用任何语言编译它</strong>——Mochi 的实现器(用 TS 写)就是本系列的产物</li></ul><p>不用 Python:Python 写解释器对读者最友好,但<strong>会让性能讨论失去说服力</strong>——后面 VM 篇章要测树遍历 vs 字节码的实际加速比,宿主语言不能太慢。</p><hr><h2 id="预计时间线" tabindex="-1">预计时间线 <a class="header-anchor" href="#预计时间线" aria-label="Permalink to &quot;预计时间线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 前端(01-09)      → 约 2 周(09 Pratt 最慢)</span></span>
<span class="line"><span>树遍历 + 进阶语义(10-19) → 约 2-3 周(14 闭包 / 16 类 是重头戏)</span></span>
<span class="line"><span>字节码 VM(20-25)        → 约 2 周(24 编译器最慢,容易卡)</span></span>
<span class="line"><span>运行时(26-30)           → 约 1-2 周(26-27 GC 最难,但 Mochi 玩具版可以收敛)</span></span></code></pre></div><p>跟其他系列的节奏建议一致:<strong>不建议连开新系列</strong>——这个系列每一篇都要在 Mochi 仓库提交代码,<strong>没动手过的篇章不算完成</strong>。</p><hr><h2 id="完成的判据" tabindex="-1">完成的判据 <a class="header-anchor" href="#完成的判据" aria-label="Permalink to &quot;完成的判据&quot;">​</a></h2><p>每一篇都要满足三件事才能打 [x]:</p><ol><li>Mochi 仓库有对应的 commit / tag,<strong><code>pnpm test</code> 全过</strong></li><li>文章里有至少一张图(AST / 字节码 / 内存布局 / 调度流程,选一张)</li><li>「工业级是怎么做的」那一段,<strong>至少给出一个 V8 / CPython / Lua / JVM 的具体文件路径或 commit</strong>——没指针就是没看源码,不能糊弄</li></ol><p>这三条任何一条没满足就当未完成,<strong>回头补</strong>——本系列最怕的就是&quot;看起来写完了,但代码不能跑&quot;。</p><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>Mochi 是为了<strong>让读者跟着写一遍</strong>而存在的玩具,<strong>不追求生产可用</strong>——所有&quot;为了简单而省略&quot;的地方都会明确标注「Mochi 这里偷懒了 / 真实语言会怎么做」,确保读者知道边界在哪里。</p><p>最终交付物有三个:</p><ol><li>30 篇文章</li><li>一个 GitHub 仓库 <code>mochi-lang</code>,按篇分 tag,每篇对应一个可运行版本</li><li>一份「从 Mochi 到读真实语言源码」的索引(CPython / V8 / Lua 关键文件指针)</li></ol>`,65)])])}const g=n(l,[["render",e]]);export{u as __pageData,g as default};
